import{_ as t,o as r,c as e,ag as o}from"./chunks/framework.OsDJF_Ea.js";const k=JSON.parse('{"title":"Task Dashboard","description":"Your personal work hub combining a kanban board with JIRA ticket sync and scan-based task creation.","frontmatter":{"title":"Task Dashboard","description":"Your personal work hub combining a kanban board with JIRA ticket sync and scan-based task creation."},"headers":[],"relativePath":"portals/task/dashboard.md","filePath":"portals/task/dashboard.md"}'),s={name:"portals/task/dashboard.md"};function n(d,a,i,h,c,l){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="task-dashboard" tabindex="-1">Task Dashboard <a class="header-anchor" href="#task-dashboard" aria-label="Permalink to &quot;Task Dashboard&quot;">​</a></h1><p><strong>Route:</strong> <code>/tm</code> · <strong>Edition:</strong> Community+</p><p>The Task Dashboard is your personal work hub. It combines a kanban board for your own tasks with quick access to JIRA ticket sync and scan-based task creation.</p><h2 id="what-s-on-the-dashboard" tabindex="-1">What&#39;s on the dashboard <a class="header-anchor" href="#what-s-on-the-dashboard" aria-label="Permalink to &quot;What&#39;s on the dashboard&quot;">​</a></h2><h3 id="kanban-board" tabindex="-1">Kanban board <a class="header-anchor" href="#kanban-board" aria-label="Permalink to &quot;Kanban board&quot;">​</a></h3><p>Tasks are organized into four columns: <strong>To Do</strong>, <strong>In Progress</strong>, <strong>In Review</strong>, and <strong>Done</strong>. Drag cards between columns to update status instantly.</p><h3 id="task-cards" tabindex="-1">Task cards <a class="header-anchor" href="#task-cards" aria-label="Permalink to &quot;Task cards&quot;">​</a></h3><p>Each card shows:</p><ul><li>Title and description preview</li><li>Priority badge (Critical / High / Medium / Low)</li><li>Due date (highlighted red if overdue)</li><li>JIRA ticket link (if synced)</li><li>Assignee and team label</li></ul><h3 id="quick-create" tabindex="-1">Quick create <a class="header-anchor" href="#quick-create" aria-label="Permalink to &quot;Quick create&quot;">​</a></h3><p>Click <strong>+ New Task</strong> in the top-right to open the task creation form directly from the dashboard without leaving the kanban view.</p><h3 id="stats-bar" tabindex="-1">Stats bar <a class="header-anchor" href="#stats-bar" aria-label="Permalink to &quot;Stats bar&quot;">​</a></h3><p>A summary row at the top shows open, in-progress, and overdue counts at a glance.</p><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody><tr><td>Create task</td><td><strong>+ New Task</strong> button or drag a card into a column</td></tr><tr><td>Move task</td><td>Drag the card to the target column</td></tr><tr><td>Edit task</td><td>Click the card title</td></tr><tr><td>Delete task</td><td>Open the card → overflow menu → Delete</td></tr><tr><td>Filter by priority</td><td>Priority filter in the toolbar</td></tr><tr><td>Filter by due date</td><td>Date range picker in the toolbar</td></tr></tbody></table>',15)])])}const u=t(s,[["render",n]]);export{k as __pageData,u as default};
